#include <iostream>
using namespace std;

int divide(int a, int b) {
 if (b == 0) {
 throw "Division by zero!"; // Throw exception
 }
 return a / b;
}

int main() {
 try {
 int result = divide(10, 0); // May throw
 cout << "Result: " << result << endl;
 }
 catch (const char* msg) { // Catch specific type
 cout << "Error: " << msg << endl;
 }
 return 0;
}

#include <iostream>
#include <stdexcept>
using namespace std;

void process(int choice) {
 try {
 if (choice == 1) throw 10;
 else if (choice == 2) throw 3.14;
 else if (choice == 3) throw runtime_error("Runtime error");
 else throw "Unknown error";
 }
 catch (int e) {
 cout << "Caught int: " << e << endl;
 }
 catch (double e) {
 cout << "Caught double: " << e << endl;
 }
 catch (runtime_error& e) {
 cout << "Caught runtime_error: " << e.what() << endl;
 }
 catch (...) {
 cout << "Caught unknown exception" << endl;
 }
}

#include <iostream>
#include <exception>
using namespace std;

class MyException : public exception {
 string msg;
public:
 MyException(const string& m) : msg(m) {}
 const char* what() const noexcept override {
 return msg.c_str();
 }
};

class BankAccount {
 double balance;
public:
 BankAccount(double b) : balance(b) {}
 void withdraw(double amount) {
 if (amount > balance)
 throw MyException("Insufficient funds!");
 balance -= amount;
 }
};

#include <iostream>
using namespace std;

class Logger {
 string name;
public:
 Logger(string n) : name(n) { cout << name << " created\n"; }
 ~Logger() { cout << name << " destroyed\n"; }
};

void level3() {
 Logger l3("Level3");
 throw 99;
}

void level2() {
 Logger l2("Level2");
 level3();
}

void level1() {
 Logger l1("Level1");
 level2();
}

int main() {
 try {
 level1();
 }
 catch (int e) {
 cout << "Caught: " << e << endl;
 }
 return 0;
}

#include <iostream>
using namespace std;

void inner() {
 try {
 throw runtime_error("Original error");
 }
 catch (runtime_error& e) {
 cout << "Inner caught: " << e.what() << endl;
 throw; // Rethrow - propagate to outer
 }
}

void outer() {
 try {
 inner();
 }
 catch (runtime_error& e) {
 cout << "Outer caught: " << e.what() << endl;
 }
}

int main() {
 outer();
 return 0;
}
